package com.droid2developers.liveslider.adapters;

import android.annotation.SuppressLint;
import android.content.Context;
import android.content.SharedPreferences;
import android.util.Log;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.ProgressBar;
import android.widget.RelativeLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.core.content.res.ResourcesCompat;
import androidx.preference.PreferenceManager;
import androidx.recyclerview.widget.RecyclerView;

import com.bumptech.glide.Glide;
import com.bumptech.glide.Priority;
import com.bumptech.glide.load.engine.DiskCacheStrategy;
import com.bumptech.glide.request.RequestOptions;
import com.google.android.material.dialog.MaterialAlertDialogBuilder;
import com.droid2developers.liveslider.R;
import com.droid2developers.liveslider.database.models.Playlist;
import com.google.android.material.progressindicator.CircularProgressIndicator;

import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.List;
import java.util.Locale;

import static com.bumptech.glide.load.resource.drawable.DrawableTransitionOptions.withCrossFade;
import static com.droid2developers.liveslider.utils.Constant.PLAYLIST_NONE;
import static com.droid2developers.liveslider.utils.Constant.TYPE_SINGLE;
import static com.droid2developers.liveslider.utils.Constant.TYPE_SLIDESHOW;
import static com.droid2developers.liveslider.utils.Constant.WALLPAPER_NONE;
import static com.droid2developers.liveslider.utils.Constant.PREF_DUAL_PLAYLIST_ENABLED;
import static com.droid2developers.liveslider.utils.Constant.PREF_LOCK_PLAYLIST;

public class PlaylistAdapter extends RecyclerView.Adapter<PlaylistAdapter.MyViewHolder> {

    private static final String TAG = PlaylistAdapter.class.getSimpleName();
    private OnItemClickListener onItemClickListener;
    private final List<Playlist> mAllPlaylist = new ArrayList<>();
    private String playlistId;
    private final SharedPreferences prefs;
    private final SharedPreferences.Editor editor;
    private final Context mContext;


    @SuppressLint("CommitPrefEdits")
    public PlaylistAdapter(Context mContext, String playlistId) {
        this.mContext = mContext;
        this.playlistId = playlistId;
        prefs = PreferenceManager.getDefaultSharedPreferences(mContext);
        editor = prefs.edit();
    }


    public interface OnItemClickListener {
        void OnItemLongClick(int position);
    }


    public void setOnItemClickListener(OnItemClickListener onItemClickListener) {
        this.onItemClickListener = onItemClickListener;
    }


    public class MyViewHolder extends RecyclerView.ViewHolder implements View.OnClickListener, View.OnLongClickListener {

        ImageView thumbIv;
        TextView count, title, creationDate;
        ProgressBar progressIndicator;
        RelativeLayout activeBadge;
        RelativeLayout lockBadge;

        MyViewHolder(View itemView) {
            super(itemView);
            itemView.setOnClickListener(this);
            itemView.setOnLongClickListener(this);

            thumbIv = itemView.findViewById(R.id.mainThumbnailId);
            title = itemView.findViewById(R.id.collectionTitleId);
            creationDate = itemView.findViewById(R.id.creationDateId);
            activeBadge = itemView.findViewById(R.id.active_badge);
            lockBadge = itemView.findViewById(R.id.lock_badge);
            progressIndicator = itemView.findViewById(R.id.progressView);
            progressIndicator.setIndeterminate(true);
        }

        @Override
        public void onClick(View view) {
            Playlist playlist = getItemList().get(getLayoutPosition());
            boolean isDualEnabled = prefs.getBoolean(PREF_DUAL_PLAYLIST_ENABLED, false);

            if (isDualEnabled) {
                // Dual mode: let user choose Home or Lock assignment
                new MaterialAlertDialogBuilder(mContext)
                        .setIcon(ResourcesCompat.getDrawable(mContext.getResources(), R.drawable.error_24dp, null))
                        .setTitle(R.string.dual_playlist_assign_title)
                        .setMessage(R.string.dual_playlist_assign_message)
                        .setCancelable(false)
                        .setPositiveButton(R.string.dual_playlist_home, (dialog, which) -> {
                            updateHomeSelection(playlist);
                            dialog.dismiss();
                        })
                        .setNeutralButton(R.string.dual_playlist_lock, (dialog, which) -> {
                            updateLockSelection(playlist);
                            dialog.dismiss();
                        })
                        .setNegativeButton(android.R.string.cancel, (dialog, which) -> dialog.dismiss())
                        .create()
                        .show();
            } else {
                // Single mode: existing flow
                new MaterialAlertDialogBuilder(mContext)
                        .setIcon(ResourcesCompat.getDrawable(mContext.getResources(), R.drawable.error_24dp, null))
                        .setTitle("Activate Playlist?")
                        .setMessage(R.string.playlist_activation)
                        .setCancelable(false)
                        .setPositiveButton("Activate", (dialog, which) -> {
                            updateSelection(playlist);
                            dialog.dismiss();
                        })
                        .setNegativeButton("Cancel", (dialog, which) -> dialog.dismiss())
                        .create()
                        .show();
            }
        }

        @Override
        public boolean onLongClick(View view) {
            onItemClickListener.OnItemLongClick(this.getLayoutPosition());
            return true;
        }
    }


    @NonNull
    @Override
    public MyViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        final View itemView = LayoutInflater.from(mContext).inflate(R.layout.item_playlist, parent, false);
        return new MyViewHolder(itemView);
    }

    @Override
    public void onBindViewHolder(@NonNull MyViewHolder holder, int position) {

        Playlist playlist = mAllPlaylist.get(position);
        String coverImage = playlist.coverImage;

        String currentPlaylist = prefs.getString("current_playlist", PLAYLIST_NONE);
        String currentLockPlaylist = prefs.getString(PREF_LOCK_PLAYLIST, PLAYLIST_NONE);
        boolean isDualEnabled = prefs.getBoolean(PREF_DUAL_PLAYLIST_ENABLED, false);
        int wallpaperType = prefs.getInt("type", TYPE_SINGLE);

        // Home active badge
        if (wallpaperType == TYPE_SLIDESHOW && currentPlaylist.equals(playlist.playlistId)) {
            holder.activeBadge.setVisibility(View.VISIBLE);
        } else {
            holder.activeBadge.setVisibility(View.GONE);
        }

        // Lock badge — only shown when dual mode is enabled
        if (isDualEnabled && !currentLockPlaylist.equals(PLAYLIST_NONE)
                && currentLockPlaylist.equals(playlist.playlistId)) {
            holder.lockBadge.setVisibility(View.VISIBLE);
        } else {
            holder.lockBadge.setVisibility(View.GONE);
        }

        // Format creation date for display
        Calendar calendar = Calendar.getInstance();
        if (playlist.createdAt != null) {
            calendar.setTime(playlist.createdAt);
        }
        int day = calendar.get(Calendar.DAY_OF_MONTH);
        String month = new SimpleDateFormat("MMMM", Locale.getDefault()).format(playlist.createdAt);
        String formattedDate = "Created on " + day + " " + month;

        // Set text content
        String itemCount = playlist.size + "+ Photos";
        holder.title.setText(itemCount);
        holder.creationDate.setText(formattedDate);

        RequestOptions options = new RequestOptions()
                .centerInside()
                .diskCacheStrategy(DiskCacheStrategy.ALL)
                .priority(Priority.HIGH);

        if (coverImage != null) {
            holder.progressIndicator.setVisibility(View.INVISIBLE);
            holder.thumbIv.setVisibility(View.VISIBLE);
            Glide.with(holder.thumbIv.getContext())
                    .load(coverImage)
                    .thumbnail(0.5f)
                    .transition(withCrossFade())
                    .apply(options)
                    .into(holder.thumbIv);
        } else {
            holder.thumbIv.setVisibility(View.INVISIBLE);
            holder.progressIndicator.setVisibility(View.VISIBLE);
        }
    }

    @Override
    public int getItemCount() {
        return mAllPlaylist.size();
    }

    @Override
    public int getItemViewType(int position) {
        return super.getItemViewType(position);
    }


    private void updateSelection(Playlist playlist) {
        if (!playlistId.equals(playlist.playlistId)) {
            editor.putInt("type", TYPE_SLIDESHOW);
            editor.putString("local_wallpaper_path", WALLPAPER_NONE);
            editor.putBoolean("double_tap", true);
            editor.putString("current_playlist", playlist.playlistId);
            editor.putBoolean("slideshow", true);
            if (editor.commit()) {
                playlistId = playlist.playlistId;
                notifyDataSetChanged();
            }
        } else {
            Toast.makeText(mContext, "Playlist already activated!", Toast.LENGTH_SHORT).show();
        }
    }

    /** Dual-mode: assign playlist to Home screen slideshow (same as updateSelection). */
    private void updateHomeSelection(Playlist playlist) {
        updateSelection(playlist);
    }

    /** Dual-mode: assign playlist to Lock screen slideshow. */
    private void updateLockSelection(Playlist playlist) {
        String currentLock = prefs.getString(PREF_LOCK_PLAYLIST, PLAYLIST_NONE);
        if (!currentLock.equals(playlist.playlistId)) {
            editor.putString(PREF_LOCK_PLAYLIST, playlist.playlistId);
            if (editor.commit()) {
                notifyDataSetChanged();
            }
        } else {
            Toast.makeText(mContext, mContext.getString(R.string.dual_playlist_already_lock), Toast.LENGTH_SHORT).show();
        }
    }

    public void addPlaylists(List<Playlist> list) {
        mAllPlaylist.addAll(list);
        notifyDataSetChanged();
    }

    public void updatePlaylist() {
        playlistId = prefs.getString("current_playlist", PLAYLIST_NONE);
    }

    public void clearList() {
        if (!mAllPlaylist.isEmpty()) {
            mAllPlaylist.clear();
            notifyDataSetChanged();
        }
    }

    public List<Playlist> getItemList() {
        return mAllPlaylist;
    }
}

package com.droid2developers.liveslider.adapters;

import android.annotation.SuppressLint;
import android.app.WallpaperInfo;
import android.app.WallpaperManager;
import android.content.Context;
import android.os.Build;
import android.content.SharedPreferences;
import android.util.Log;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.ProgressBar;
import android.widget.RelativeLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.core.content.res.ResourcesCompat;
import androidx.preference.PreferenceManager;
import androidx.recyclerview.widget.RecyclerView;

import com.bumptech.glide.Glide;
import com.bumptech.glide.Priority;
import com.bumptech.glide.load.engine.DiskCacheStrategy;
import com.bumptech.glide.request.RequestOptions;
import com.google.android.material.dialog.MaterialAlertDialogBuilder;
import com.droid2developers.liveslider.R;
import com.droid2developers.liveslider.database.models.Playlist;
import com.google.android.material.progressindicator.CircularProgressIndicator;

import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.List;
import java.util.Locale;

import static com.bumptech.glide.load.resource.drawable.DrawableTransitionOptions.withCrossFade;
import static com.droid2developers.liveslider.utils.Constant.PLAYLIST_NONE;
import static com.droid2developers.liveslider.utils.Constant.TYPE_SINGLE;
import static com.droid2developers.liveslider.utils.Constant.TYPE_SLIDESHOW;
import static com.droid2developers.liveslider.utils.Constant.WALLPAPER_NONE;
import static com.droid2developers.liveslider.utils.Constant.PREF_DUAL_PLAYLIST_ENABLED;
import static com.droid2developers.liveslider.utils.Constant.PREFS_LOCK;

public class PlaylistAdapter extends RecyclerView.Adapter<PlaylistAdapter.MyViewHolder> {

    private static final String TAG = PlaylistAdapter.class.getSimpleName();
    private OnItemClickListener onItemClickListener;
    private final List<Playlist> mAllPlaylist = new ArrayList<>();
    private String playlistId;
    private final SharedPreferences prefs;
    private final SharedPreferences.Editor editor;
    /** Isolated prefs for LockLiveWallpaperService — written here, read by the lock engine. */
    private final SharedPreferences lockPrefs;
    private final Context mContext;


    @SuppressLint("CommitPrefEdits")
    public PlaylistAdapter(Context mContext, String playlistId) {
        this.mContext = mContext;
        this.playlistId = playlistId;
        prefs     = PreferenceManager.getDefaultSharedPreferences(mContext);
        editor    = prefs.edit();
        lockPrefs = mContext.getSharedPreferences(PREFS_LOCK, Context.MODE_PRIVATE);
    }


    public interface OnItemClickListener {
        void OnItemLongClick(int position);
    }


    public void setOnItemClickListener(OnItemClickListener onItemClickListener) {
        this.onItemClickListener = onItemClickListener;
    }


    public class MyViewHolder extends RecyclerView.ViewHolder implements View.OnClickListener, View.OnLongClickListener {

        ImageView thumbIv;
        TextView count, title, creationDate;
        ProgressBar progressIndicator;
        RelativeLayout activeBadge;
        RelativeLayout lockBadge;

        MyViewHolder(View itemView) {
            super(itemView);
            itemView.setOnClickListener(this);
            itemView.setOnLongClickListener(this);

            thumbIv = itemView.findViewById(R.id.mainThumbnailId);
            title = itemView.findViewById(R.id.collectionTitleId);
            creationDate = itemView.findViewById(R.id.creationDateId);
            activeBadge = itemView.findViewById(R.id.active_badge);
            lockBadge = itemView.findViewById(R.id.lock_badge);
            progressIndicator = itemView.findViewById(R.id.progressView);
            progressIndicator.setIndeterminate(true);
        }

        @Override
        public void onClick(View view) {
            Playlist playlist = getItemList().get(getLayoutPosition());

            // ── Query actual live wallpaper assignment ────────────────────────
            WallpaperManager wm = WallpaperManager.getInstance(mContext);
            String pkg = mContext.getPackageName();

            WallpaperInfo homeInfo = wm.getWallpaperInfo();
            boolean isActiveOnHome = homeInfo != null && homeInfo.getPackageName().equals(pkg);
            boolean isActiveOnLock;

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.UPSIDE_DOWN_CAKE) {
                try {
                    WallpaperInfo lockInfo = wm.getWallpaperInfo(WallpaperManager.FLAG_LOCK);
                    // null means lock mirrors home — LockLiveWallpaperService is NOT explicitly set
                    isActiveOnLock = lockInfo != null && lockInfo.getPackageName().equals(pkg);
                } catch (Throwable t) {
                    isActiveOnLock = false;
                }
            } else {
                isActiveOnLock = isActiveOnHome; // pre-API 34: same surface
            }

            // ── Not activated at all → guide user to Activate tab ────────────
            if (!isActiveOnHome && !isActiveOnLock) {
                new MaterialAlertDialogBuilder(mContext)
                        .setTitle(R.string.activate_not_live_title)
                        .setMessage(R.string.activate_not_live_msg)
                        .setPositiveButton(android.R.string.ok, null)
                        .show();
                return;
            }

            // ── Both home and lock are live → offer choice ───────────────────
            if (isActiveOnHome && isActiveOnLock) {
                new MaterialAlertDialogBuilder(mContext)
                        .setIcon(ResourcesCompat.getDrawable(mContext.getResources(), R.drawable.error_24dp, null))
                        .setTitle(R.string.dual_playlist_assign_title)
                        .setMessage(R.string.dual_playlist_assign_message)
                        .setCancelable(false)
                        .setPositiveButton(R.string.dual_playlist_home, (dialog, which) -> {
                            updateHomeSelection(playlist);
                            dialog.dismiss();
                        })
                        .setNeutralButton(R.string.dual_playlist_lock, (dialog, which) -> {
                            updateLockSelection(playlist);
                            dialog.dismiss();
                        })
                        .setNegativeButton(android.R.string.cancel, (dialog, which) -> dialog.dismiss())
                        .create()
                        .show();
                return;
            }

            // ── Only lock is live → activate for lock directly ───────────────
            if (isActiveOnLock) {
                new MaterialAlertDialogBuilder(mContext)
                        .setIcon(ResourcesCompat.getDrawable(mContext.getResources(), R.drawable.error_24dp, null))
                        .setTitle(R.string.dual_playlist_assign_title)
                        .setMessage(R.string.playlist_activation)
                        .setCancelable(false)
                        .setPositiveButton(R.string.dual_playlist_lock, (dialog, which) -> {
                            updateLockSelection(playlist);
                            dialog.dismiss();
                        })
                        .setNegativeButton(android.R.string.cancel, (dialog, which) -> dialog.dismiss())
                        .create()
                        .show();
                return;
            }

            // ── Only home is live → activate for home ────────────────────────
            new MaterialAlertDialogBuilder(mContext)
                    .setIcon(ResourcesCompat.getDrawable(mContext.getResources(), R.drawable.error_24dp, null))
                    .setTitle("Activate Playlist?")
                    .setMessage(R.string.playlist_activation)
                    .setCancelable(false)
                    .setPositiveButton("Activate", (dialog, which) -> {
                        updateHomeSelection(playlist);
                        dialog.dismiss();
                    })
                    .setNegativeButton("Cancel", (dialog, which) -> dialog.dismiss())
                    .create()
                    .show();
        }

        @Override
        public boolean onLongClick(View view) {
            onItemClickListener.OnItemLongClick(this.getLayoutPosition());
            return true;
        }
    }


    @NonNull
    @Override
    public MyViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        final View itemView = LayoutInflater.from(mContext).inflate(R.layout.item_playlist, parent, false);
        return new MyViewHolder(itemView);
    }

    @Override
    public void onBindViewHolder(@NonNull MyViewHolder holder, int position) {

        Playlist playlist = mAllPlaylist.get(position);
        String coverImage = playlist.coverImage;

        String currentPlaylist     = prefs.getString("current_playlist", PLAYLIST_NONE);
        String currentLockPlaylist = lockPrefs.getString("current_playlist", PLAYLIST_NONE);
        int wallpaperType          = prefs.getInt("type", TYPE_SINGLE);

        // Home active badge
        if (wallpaperType == TYPE_SLIDESHOW && currentPlaylist.equals(playlist.playlistId)) {
            holder.activeBadge.setVisibility(View.VISIBLE);
        } else {
            holder.activeBadge.setVisibility(View.GONE);
        }

        // Lock badge — shown whenever this playlist is active on the lock service
        if (!currentLockPlaylist.equals(PLAYLIST_NONE) && currentLockPlaylist.equals(playlist.playlistId)) {
            holder.lockBadge.setVisibility(View.VISIBLE);
        } else {
            holder.lockBadge.setVisibility(View.GONE);
        }

        // Format creation date for display
        Calendar calendar = Calendar.getInstance();
        if (playlist.createdAt != null) {
            calendar.setTime(playlist.createdAt);
        }
        int day = calendar.get(Calendar.DAY_OF_MONTH);
        String month = new SimpleDateFormat("MMMM", Locale.getDefault()).format(playlist.createdAt);
        String formattedDate = "Created on " + day + " " + month;

        // Set text content
        String itemCount = playlist.size + "+ Photos";
        holder.title.setText(itemCount);
        holder.creationDate.setText(formattedDate);

        RequestOptions options = new RequestOptions()
                .centerInside()
                .diskCacheStrategy(DiskCacheStrategy.ALL)
                .priority(Priority.HIGH);

        if (coverImage != null) {
            holder.progressIndicator.setVisibility(View.INVISIBLE);
            holder.thumbIv.setVisibility(View.VISIBLE);
            Glide.with(holder.thumbIv.getContext())
                    .load(coverImage)
                    .thumbnail(0.5f)
                    .transition(withCrossFade())
                    .apply(options)
                    .into(holder.thumbIv);
        } else {
            holder.thumbIv.setVisibility(View.INVISIBLE);
            holder.progressIndicator.setVisibility(View.VISIBLE);
        }
    }

    @Override
    public int getItemCount() {
        return mAllPlaylist.size();
    }

    @Override
    public int getItemViewType(int position) {
        return super.getItemViewType(position);
    }


    private void updateSelection(Playlist playlist) {
        if (!playlistId.equals(playlist.playlistId)) {
            editor.putInt("type", TYPE_SLIDESHOW);
            editor.putString("local_wallpaper_path", WALLPAPER_NONE);
            editor.putBoolean("double_tap", true);
            editor.putString("current_playlist", playlist.playlistId);
            editor.putBoolean("slideshow", true);
            if (editor.commit()) {
                playlistId = playlist.playlistId;
                notifyDataSetChanged();
            }
        } else {
            Toast.makeText(mContext, "Playlist already activated!", Toast.LENGTH_SHORT).show();
        }
    }

    /** Dual-mode: assign playlist to Home screen slideshow (same as updateSelection). */
    private void updateHomeSelection(Playlist playlist) {
        updateSelection(playlist);
    }

    /**
     * Dual-mode: assign playlist to the Lock screen by writing directly into
     * the lock service's isolated SharedPreferences file.
     * LockLiveWallpaperService.onSharedPreferenceChanged() will fire on
     * "current_playlist" and call setCurrentPlaylist() to reload the renderer.
     */
    private void updateLockSelection(Playlist playlist) {
        String currentLock = lockPrefs.getString("current_playlist", PLAYLIST_NONE);
        if (!currentLock.equals(playlist.playlistId)) {
            lockPrefs.edit()
                     .putInt("type", TYPE_SLIDESHOW)
                     .putBoolean("slideshow", true)
                     .putBoolean("double_tap", true)
                     .putString("local_wallpaper_path", WALLPAPER_NONE)
                     .putString("current_playlist", playlist.playlistId)
                     .apply();
            notifyDataSetChanged();
        } else {
            Toast.makeText(mContext, mContext.getString(R.string.dual_playlist_already_lock),
                    Toast.LENGTH_SHORT).show();
        }
    }

    public void addPlaylists(List<Playlist> list) {
        mAllPlaylist.addAll(list);
        notifyDataSetChanged();
    }

    public void updatePlaylist() {
        playlistId = prefs.getString("current_playlist", PLAYLIST_NONE);
    }

    public void clearList() {
        if (!mAllPlaylist.isEmpty()) {
            mAllPlaylist.clear();
            notifyDataSetChanged();
        }
    }

    public List<Playlist> getItemList() {
        return mAllPlaylist;
    }
}

package com.droid2developers.liveslider.provider;

import android.content.ContentProvider;
import android.content.ContentValues;
import android.content.UriMatcher;
import android.database.Cursor;
import android.net.Uri;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.util.Log;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import java.io.FileNotFoundException;

/**
 * Samsung SEP (Samsung Experience Platform) Wallpaper Provider
 * This provider is required for Samsung devices to support live wallpaper screenshots
 * and preview functionality in the system wallpaper picker.
 */
public class SepWallpaperProvider extends ContentProvider {
    private static final String TAG = "SepWallpaperProvider";
    private static final String AUTHORITY = "com.droid2developers.liveslider.provider.sepwallpaper";

    private static final int SCREENSHOT = 1;
    private static final UriMatcher sUriMatcher = new UriMatcher(UriMatcher.NO_MATCH);

    static {
        sUriMatcher.addURI(AUTHORITY, "screenshot", SCREENSHOT);
    }

    @Override
    public boolean onCreate() {
        Log.d(TAG, "SepWallpaperProvider created");
        return true;
    }

    @Nullable
    @Override
    public Cursor query(@NonNull Uri uri, @Nullable String[] projection, @Nullable String selection,
                       @Nullable String[] selectionArgs, @Nullable String sortOrder) {
        Log.d(TAG, "query() called with uri: " + uri);
        return null;
    }

    @Nullable
    @Override
    public String getType(@NonNull Uri uri) {
        switch (sUriMatcher.match(uri)) {
            case SCREENSHOT:
                return "image/png";
            default:
                return null;
        }
    }

    @Nullable
    @Override
    public Uri insert(@NonNull Uri uri, @Nullable ContentValues values) {
        Log.d(TAG, "insert() called with uri: " + uri);
        return null;
    }

    @Override
    public int delete(@NonNull Uri uri, @Nullable String selection, @Nullable String[] selectionArgs) {
        Log.d(TAG, "delete() called with uri: " + uri);
        return 0;
    }

    @Override
    public int update(@NonNull Uri uri, @Nullable ContentValues values, @Nullable String selection,
                     @Nullable String[] selectionArgs) {
        Log.d(TAG, "update() called with uri: " + uri);
        return 0;
    }

    @Nullable
    @Override
    public ParcelFileDescriptor openFile(@NonNull Uri uri, @NonNull String mode) throws FileNotFoundException {
        Log.d(TAG, "openFile() called with uri: " + uri + ", mode: " + mode);

        switch (sUriMatcher.match(uri)) {
            case SCREENSHOT:
                // Samsung system is requesting a screenshot of the live wallpaper
                // For now, return null to indicate no screenshot available
                // You could implement actual screenshot functionality here if needed
                Log.i(TAG, "Screenshot requested for live wallpaper");
                return null;
            default:
                throw new FileNotFoundException("Unknown URI: " + uri);
        }
    }

    @Nullable
    @Override
    public Bundle call(@NonNull String method, @Nullable String arg, @Nullable Bundle extras) {
        Log.d(TAG, "call() method: " + method + ", arg: " + arg);

        // Handle Samsung-specific method calls here if needed
        Bundle result = new Bundle();

        switch (method) {
            case "getScreenshot":
                // Samsung is requesting wallpaper screenshot
                Log.i(TAG, "getScreenshot method called");
                result.putBoolean("success", false); // Indicate no screenshot available
                break;
            default:
                Log.w(TAG, "Unknown method: " + method);
                break;
        }

        return result;
    }
}

package com.droid2developers.liveslider.utils;

import android.os.Environment;

import java.util.concurrent.TimeUnit;

public class Constant {

    public static String DB_NAME = "db_live_wallpapers";

    public static final String HEADER = "wallpaper_";
    public static final String DEFAULT_WALLPAPER_NAME = "wallpaper_default.jpg";
    private static final String ASSETS_PATH = "file:///android_asset/";
    public static final String DEFAULT_LOCAL_PATH = Constant.ASSETS_PATH + Constant.DEFAULT_WALLPAPER_NAME;

    //slideshow timer constants
    public static final long DEFAULT_SLIDESHOW_TIME = 15 * 60 * 1000;
    public static final long MINIMUM_SLIDESHOW_TIME = 2 * 1000;


    // Image file formats
    public static final String PNG = ".png";
    public static final String JPG = ".jpg";

    /** Wallpaper PlaylistId Types
     * if DEFAULT - default assets wallpaper
     * if CUSTOM - single local wallpapers
     * id PlaylistId - wallpaper from a playlist
     */
    public static final String DEFAULT = "Default";
    public static final String CUSTOM = "Custom";

    // LiveWallpaper Types to enable/disable different formats
    public static final int TYPE_SINGLE = 0;
    public static final int TYPE_AUTO = 1;
    public static final int TYPE_SLIDESHOW = 2;

    // Calibration Mode Constants
    public static final int CALIBRATION_DEFAULT = 0;
    public static final int CALIBRATION_VERTICAL = 1;
    public static final int CALIBRATION_DYNAMIC = 2;

    // Transition Effect Constants  (stored in prefs as "transition_effect")
    public static final int TRANSITION_FADE     = 0;
    public static final int TRANSITION_DISSOLVE = 1;
    public static final int TRANSITION_PIXELATE = 2;
    public static final int TRANSITION_WIPE     = 3; // horizontal left→right sweep
    public static final int TRANSITION_BLUR     = 4; // Gaussian blur crossfade
    public static final int TRANSITION_ZOOM     = 5; // grow from screen centre

    // Animation Speed Constants (stored in prefs as "animation_speed")
    public static final int ANIMATION_SPEED_QUARTER = 4; // 0.25x — 2.4s
    public static final int ANIMATION_SPEED_HALF    = 0; // 0.5x  — 1.2s
    public static final int ANIMATION_SPEED_NORMAL  = 1; // 1x    — 0.6s (default)
    public static final int ANIMATION_SPEED_DOUBLE  = 2; // 2x    — 0.3s
    public static final int ANIMATION_SPEED_TRIPLE  = 3; // 3x    — 0.15s
    public static final int ANIMATION_SPEED_STUPID  = 5; // 4x    — 0.05s

    public static final String PLAYLIST_NONE = "none";
    public static final String WALLPAPER_NONE = "none";

    public static final String WORKER_KEY_PLAYLIST_ID = "playlist_id";
    public static final String PREF_CHANGE_ON_UNLOCK  = "change_on_unlock";

    // Dual playlist (separate home / lock screen playlists)
    public static final String PREF_DUAL_PLAYLIST_ENABLED = "dual_playlist_enabled";
    public static final String PREF_LOCK_PLAYLIST          = "lock_playlist";



    public enum StorageState {NOT_AVAILABLE, WRITEABLE, READ_ONLY}
    public StorageState getExternalStorageState() {
        StorageState result = StorageState.NOT_AVAILABLE;
        String state = Environment.getExternalStorageState();
        if (Environment.MEDIA_MOUNTED.equals(state)) {
            return StorageState.WRITEABLE;
        } else if (Environment.MEDIA_MOUNTED_READ_ONLY.equals(state)) {
            return StorageState.READ_ONLY;
        }
        return result;
    }


    public static String getTimeText(long timeInMillis) {
        String timeString = "Wallpaper changes in every ";
        long hours = TimeUnit.MILLISECONDS.toHours(timeInMillis);
        long minutes = TimeUnit.MILLISECONDS.toMinutes(timeInMillis) -
                TimeUnit.HOURS.toMinutes(hours);
        long seconds = TimeUnit.MILLISECONDS.toSeconds(timeInMillis) -
                TimeUnit.MINUTES.toSeconds(TimeUnit.MILLISECONDS.toMinutes(timeInMillis));

        if (hours > 0) timeString = timeString + hours + " hours ";
        if (minutes > 0) timeString = timeString + minutes + " minutes ";
        if (seconds > 0) timeString = timeString + seconds + " seconds ";
        return timeString;
    }

    // Phone face orientation constants
    public static final int FACE_UNKNOWN = -1;
    public static final int FACE_PORTRAIT_UP = 0;      // Normal holding
    public static final int FACE_LANDSCAPE_LEFT = 1;   // Rotated left
    public static final int FACE_LANDSCAPE_RIGHT = 2;  // Rotated right
    public static final int FACE_PORTRAIT_DOWN = 3;    // Upside down
    public static final int FACE_FLAT_UP = 4;          // Lying flat, screen up
    public static final int FACE_FLAT_DOWN = 5;        // Lying flat, screen down

    public static String getFaceName(int face) {
        switch (face) {
            case FACE_PORTRAIT_UP: return "PORTRAIT_UP";
            case FACE_LANDSCAPE_LEFT: return "LANDSCAPE_LEFT";
            case FACE_LANDSCAPE_RIGHT: return "LANDSCAPE_RIGHT";
            case FACE_PORTRAIT_DOWN: return "PORTRAIT_DOWN";
            case FACE_FLAT_UP: return "FLAT_UP";
            case FACE_FLAT_DOWN: return "FLAT_DOWN";
            default: return "UNKNOWN";
        }
    }

    public static String getFaceNameReadable(int face) {
        switch (face) {
            case FACE_PORTRAIT_UP: return "FACING TOP";
            case FACE_LANDSCAPE_LEFT: return "FACING LEFT";
            case FACE_LANDSCAPE_RIGHT: return "FACING RIGHT";
            case FACE_PORTRAIT_DOWN: return "FACING BOTTOM";
            case FACE_FLAT_UP: return "DEFAULT";
            case FACE_FLAT_DOWN: return "INVERTED";
            default: return "UNKNOWN";
        }
    }
}

