package com.droid2developers.liveslider.views.fragments;

import android.app.WallpaperInfo;
import android.app.WallpaperManager;
import android.content.ActivityNotFoundException;
import android.content.ComponentName;
import android.content.Intent;
import android.graphics.Color;
import android.os.Build;
import android.os.Bundle;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import android.util.Log;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import android.widget.Toast;
import com.droid2developers.liveslider.live_wallpaper.LiveWallpaperService;
import com.droid2developers.liveslider.R;
import com.google.android.material.card.MaterialCardView;

public class ActivateFragment extends Fragment {

    private static final String TAG = ActivateFragment.class.getSimpleName();

    private TextView homeStatusText;
    private TextView lockStatusText;
    private MaterialCardView homeStatusCard;
    private MaterialCardView lockStatusCard;

    @Nullable
    @Override
    public View onCreateView(LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_activate, container, false);

        homeStatusText = view.findViewById(R.id.homeStatusText);
        lockStatusText = view.findViewById(R.id.lockStatusText);
        homeStatusCard = view.findViewById(R.id.homeStatusCard);
        lockStatusCard = view.findViewById(R.id.lockStatusCard);

        view.findViewById(R.id.activate_button).setOnClickListener(v -> {
            try {
                startActivity(new Intent(WallpaperManager.ACTION_CHANGE_LIVE_WALLPAPER)
                        .putExtra(WallpaperManager.EXTRA_LIVE_WALLPAPER_COMPONENT,
                                new ComponentName(requireContext(), LiveWallpaperService.class))
                        .addFlags(Intent.FLAG_ACTIVITY_NEW_TASK));
            } catch (ActivityNotFoundException e) {
                Log.d(TAG, "onClick: ", e);
                try {
                    startActivity(new Intent(WallpaperManager.ACTION_LIVE_WALLPAPER_CHOOSER)
                            .addFlags(Intent.FLAG_ACTIVITY_NEW_TASK));
                } catch (ActivityNotFoundException e2) {
                    Log.d(TAG, "onClick: ", e2);
                    Toast.makeText(getContext(), R.string
                            .toast_failed_launch_wallpaper_chooser, Toast.LENGTH_LONG).show();
                }
            }
        });

        return view;
    }

    @Override
    public void onViewCreated(View view, @Nullable Bundle savedInstanceState) {
        view.getRootView().setBackgroundColor(Color.argb(153, 35, 35, 35));
    }

    @Override
    public void onResume() {
        super.onResume();
        refreshWallpaperStatus();
    }

    /**
     * Queries WallpaperManager to show which surfaces this live wallpaper is active on.
     *
     * Home slot (FLAG_SYSTEM):
     *   {@code getWallpaperInfo()} — public API since level 5, no permissions needed.
     *
     * Lock slot (FLAG_LOCK):
     *   {@code getWallpaperInfo(FLAG_LOCK)} is a PUBLIC method in API 36
     *   (confirmed from SDK source — no @SystemApi / @hide annotation).
     *   Guarded with >= API 34 and try-catch in case it is absent on API 34/35 firmware.
     *   Return values:
     *     • our WallpaperInfo  → explicitly assigned to lock screen      →  ✓ (blue)
     *     • null + home active → lock inherits home; our wallpaper shown  →  ↕ (lighter blue)
     *     • null + home inactive / different pkg → not shown on lock      →  ✗ (neutral)
     *
     *   Pre-API 34: live wallpapers always occupy BOTH surfaces when set
     *               → mirror home result.
     */
    private void refreshWallpaperStatus() {
        if (getContext() == null || homeStatusText == null) return;

        WallpaperManager wm = WallpaperManager.getInstance(requireContext());
        String pkg = requireContext().getPackageName();

        // ── Home chip ─────────────────────────────────────────────────────────
        WallpaperInfo homeInfo = wm.getWallpaperInfo();
        boolean isActiveOnHome = homeInfo != null && homeInfo.getPackageName().equals(pkg);

        if (isActiveOnHome) {
            homeStatusText.setText(R.string.wallpaper_status_home_active);
            homeStatusCard.setCardBackgroundColor(Color.argb(80, 76, 175, 80));    // green
        } else {
            homeStatusText.setText(R.string.wallpaper_status_home_inactive);
            homeStatusCard.setCardBackgroundColor(Color.argb(50, 255, 255, 255));  // neutral
        }

        // ── Lock chip ─────────────────────────────────────────────────────────
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.UPSIDE_DOWN_CAKE) {
            try {
                WallpaperInfo lockInfo = wm.getWallpaperInfo(WallpaperManager.FLAG_LOCK);

                if (lockInfo != null && lockInfo.getPackageName().equals(pkg)) {
                    // Explicitly assigned to the lock slot
                    lockStatusText.setText(R.string.wallpaper_status_lock_active);
                    lockStatusCard.setCardBackgroundColor(Color.argb(80, 33, 150, 243)); // blue

                } else if (lockInfo == null && isActiveOnHome) {
                    // Lock slot not separately configured → inherits home wallpaper.
                    // Our live wallpaper IS rendered on the lock screen.
                    lockStatusText.setText(R.string.wallpaper_status_lock_same_as_home);
                    lockStatusCard.setCardBackgroundColor(Color.argb(60, 33, 150, 243)); // lighter blue

                } else {
                    // Lock has a different wallpaper (static or another live wp), or home
                    // is also not ours — we are NOT shown on the lock screen.
                    lockStatusText.setText(R.string.wallpaper_status_lock_inactive);
                    lockStatusCard.setCardBackgroundColor(Color.argb(50, 255, 255, 255)); // neutral
                }

            } catch (Throwable t) {
                // getWallpaperInfo(FLAG_LOCK) not present on this firmware (API 34/35 edge case)
                // Fall back to same-as-home behaviour
                lockStatusText.setText(isActiveOnHome
                        ? R.string.wallpaper_status_lock_same_as_home
                        : R.string.wallpaper_status_lock_inactive);
                lockStatusCard.setCardBackgroundColor(isActiveOnHome
                        ? Color.argb(60, 33, 150, 243)
                        : Color.argb(50, 255, 255, 255));
            }

        } else {
            // Pre-API 34: live wallpapers always occupy BOTH surfaces when set
            if (isActiveOnHome) {
                lockStatusText.setText(R.string.wallpaper_status_lock_active);
                lockStatusCard.setCardBackgroundColor(Color.argb(80, 33, 150, 243));
            } else {
                lockStatusText.setText(R.string.wallpaper_status_lock_inactive);
                lockStatusCard.setCardBackgroundColor(Color.argb(50, 255, 255, 255));
            }
        }
    }
}

package com.droid2developers.liveslider.views.fragments;

import android.app.WallpaperInfo;
import android.app.WallpaperManager;
import android.content.ActivityNotFoundException;
import android.content.ComponentName;
import android.content.Intent;
import android.content.SharedPreferences;
import android.content.res.ColorStateList;
import android.graphics.Color;
import android.os.Build;
import android.os.Bundle;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.preference.PreferenceManager;
import android.util.Log;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;
import com.droid2developers.liveslider.live_wallpaper.LiveWallpaperService;
import com.droid2developers.liveslider.live_wallpaper.LockLiveWallpaperService;
import com.droid2developers.liveslider.R;
import com.google.android.material.card.MaterialCardView;

import static com.droid2developers.liveslider.utils.Constant.DEFAULT_LOCAL_PATH;
import static com.droid2developers.liveslider.utils.Constant.DEFAULT_LOCK_LOCAL_PATH;
import static com.droid2developers.liveslider.utils.Constant.PREF_DUAL_PLAYLIST_ENABLED;

public class ActivateFragment extends Fragment {

    private static final String TAG = ActivateFragment.class.getSimpleName();

    // Button views
    private MaterialCardView activateButton;
    private TextView activateButtonLabel;
    private ImageView activateButtonIcon;
    private TextView activateHintText;

    // Status chip views
    private TextView homeStatusText;
    private TextView lockStatusText;
    private MaterialCardView homeStatusCard;
    private MaterialCardView lockStatusCard;

    // Cached live-wallpaper state (refreshed in onResume)
    private boolean isActiveOnHome      = false;
    private boolean isActiveOnLock      = false;
    /** True when the lock screen is mirroring home but no LockLiveWallpaperService is set. */
    private boolean isLockInheritsHome  = false;

    private SharedPreferences prefs;
    private SharedPreferences.Editor editor;

    // ── Lifecycle ────────────────────────────────────────────────────────────

    @Nullable
    @Override
    public View onCreateView(LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_activate, container, false);

        prefs  = PreferenceManager.getDefaultSharedPreferences(requireContext());
        editor = prefs.edit();

        activateButton      = view.findViewById(R.id.activate_button);
        activateButtonLabel = view.findViewById(R.id.activateButtonLabel);
        activateButtonIcon  = view.findViewById(R.id.activateButtonIcon);
        activateHintText    = view.findViewById(R.id.activateHintText);

        homeStatusText = view.findViewById(R.id.homeStatusText);
        lockStatusText = view.findViewById(R.id.lockStatusText);
        homeStatusCard = view.findViewById(R.id.homeStatusCard);
        lockStatusCard = view.findViewById(R.id.lockStatusCard);

        // Single click listener – targets the right service based on cached state
        activateButton.setOnClickListener(v -> onActivateClicked());

        return view;
    }

    @Override
    public void onViewCreated(View view, @Nullable Bundle savedInstanceState) {
        view.getRootView().setBackgroundColor(Color.argb(153, 35, 35, 35));
    }

    @Override
    public void onResume() {
        super.onResume();
        refreshWallpaperStatus();
    }

    // ── Button click ─────────────────────────────────────────────────────────

    private void onActivateClicked() {
        if (!isActiveOnHome) {
            // ── State 1: no live wallpaper yet → launch main service ─────────
            editor.putString("local_wallpaper_path", DEFAULT_LOCAL_PATH)
                  .putBoolean("default_wallpaper", true)
                  .apply();
            launchWallpaperChooser(LiveWallpaperService.class);

        } else if (!isActiveOnLock) {
            // ── State 2: home is set, lock is not → launch lock service ──────
            // Pre-set lock prefs with the lock-default image so the chooser
            // preview already shows a different image from the home service.
            SharedPreferences lockPrefs = requireContext()
                    .getSharedPreferences("prefs_lock", requireContext().MODE_PRIVATE);
            if (!lockPrefs.contains("local_wallpaper_path")) {
                lockPrefs.edit()
                         .putString("local_wallpaper_path", DEFAULT_LOCK_LOCAL_PATH)
                         .putBoolean("default_wallpaper", true)
                         .apply();
            }
            editor.putBoolean(PREF_DUAL_PLAYLIST_ENABLED, true).apply();
            launchWallpaperChooser(LockLiveWallpaperService.class);

        } else {
            // ── State 3: both active → offer re-activate choice via toast ────
            Toast.makeText(getContext(),
                    "Both Home & Lock are active. Use the Home tab to change wallpapers.",
                    Toast.LENGTH_LONG).show();
        }
    }

    // ── Chooser launch ───────────────────────────────────────────────────────

    private void launchWallpaperChooser(Class<?> serviceClass) {
        try {
            startActivity(new Intent(WallpaperManager.ACTION_CHANGE_LIVE_WALLPAPER)
                    .putExtra(WallpaperManager.EXTRA_LIVE_WALLPAPER_COMPONENT,
                            new ComponentName(requireContext(), serviceClass))
                    .addFlags(Intent.FLAG_ACTIVITY_NEW_TASK));
        } catch (ActivityNotFoundException e) {
            Log.d(TAG, "Primary intent failed", e);
            try {
                startActivity(new Intent(WallpaperManager.ACTION_LIVE_WALLPAPER_CHOOSER)
                        .addFlags(Intent.FLAG_ACTIVITY_NEW_TASK));
            } catch (ActivityNotFoundException e2) {
                Toast.makeText(getContext(), R.string.toast_failed_launch_wallpaper_chooser,
                        Toast.LENGTH_LONG).show();
            }
        }
    }

    // ── Status refresh ───────────────────────────────────────────────────────

    private void refreshWallpaperStatus() {
        if (getContext() == null || activateButton == null) return;

        WallpaperManager wm  = WallpaperManager.getInstance(requireContext());
        String pkg           = requireContext().getPackageName();

        // ── Query home surface ────────────────────────────────────────────────
        WallpaperInfo homeInfo = wm.getWallpaperInfo();
        isActiveOnHome = homeInfo != null
                && homeInfo.getPackageName().equals(pkg)
                && LiveWallpaperService.class.getName().equals(homeInfo.getServiceName());

        // Reset lock state before querying
        isActiveOnLock     = false;
        isLockInheritsHome = false;

        // ── Query lock surface ────────────────────────────────────────────────
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.UPSIDE_DOWN_CAKE) {
            try {
                WallpaperInfo lockInfo = wm.getWallpaperInfo(WallpaperManager.FLAG_LOCK);
                if (lockInfo != null
                        && lockInfo.getPackageName().equals(pkg)
                        && LockLiveWallpaperService.class.getName().equals(lockInfo.getServiceName())) {
                    // LockLiveWallpaperService is explicitly running on the lock screen
                    isActiveOnLock = true;
                } else if (lockInfo == null && isActiveOnHome) {
                    // Lock screen is mirroring the home wallpaper — no separate lock service.
                    // isActiveOnLock stays false so the button still offers "Activate Lock Screen".
                    isLockInheritsHome = true;
                }
                // If lockInfo != null but belongs to a different package/service,
                // both flags stay false — lock screen has something else entirely.
            } catch (Throwable t) {
                Log.w(TAG, "getWallpaperInfo(FLAG_LOCK) threw: " + t.getMessage());
                // Cannot determine; keep both false so button remains usable.
            }
        } else {
            // Pre-API 34: a single live wallpaper covers both surfaces automatically.
            isActiveOnLock = isActiveOnHome;
        }

        // ── Update button appearance ──────────────────────────────────────────
        updateButtonAppearance();

        // ── Update status chips ───────────────────────────────────────────────
        updateStatusChips();
    }

    private void updateButtonAppearance() {
        if (!isActiveOnHome) {
            // Not activated yet
            activateButtonLabel.setText(R.string.activate);
            activateHintText.setText(R.string.activate_hint_default);
            activateButton.setStrokeColor(ColorStateList.valueOf(Color.parseColor("#AAAAAA")));
            activateButtonIcon.setImageResource(R.drawable.ic_nav_activate);
            activateButtonIcon.setColorFilter(Color.parseColor("#333333"));

        } else if (!isActiveOnLock) {
            // Home is set, lock is not
            activateButtonLabel.setText(R.string.activate_label_lock);
            activateHintText.setText(R.string.activate_hint_lock);
            activateButton.setStrokeColor(ColorStateList.valueOf(Color.parseColor("#2196F3")));
            activateButtonIcon.setImageResource(R.drawable.ic_lock_24dp);
            activateButtonIcon.setColorFilter(Color.parseColor("#2196F3"));

        } else {
            // Both active
            activateButtonLabel.setText(R.string.activate_label_active);
            activateHintText.setText(R.string.activate_hint_both);
            activateButton.setStrokeColor(ColorStateList.valueOf(Color.parseColor("#4CAF50")));
            activateButtonIcon.setImageResource(R.drawable.ic_nav_activate);
            activateButtonIcon.setColorFilter(Color.parseColor("#4CAF50"));
        }
    }

    private void updateStatusChips() {
        // Home chip
        if (isActiveOnHome) {
            homeStatusText.setText(R.string.wallpaper_status_home_active);
            homeStatusCard.setCardBackgroundColor(Color.argb(80, 76, 175, 80));
        } else {
            homeStatusText.setText(R.string.wallpaper_status_home_inactive);
            homeStatusCard.setCardBackgroundColor(Color.argb(50, 255, 255, 255));
        }

        // Lock chip — three distinct states
        if (isActiveOnLock) {
            // LockLiveWallpaperService is explicitly set on lock screen
            lockStatusText.setText(R.string.wallpaper_status_lock_active);
            lockStatusCard.setCardBackgroundColor(Color.argb(80, 33, 150, 243));
        } else if (isLockInheritsHome) {
            // Lock screen is mirroring the home live wallpaper (no separate lock service)
            lockStatusText.setText(R.string.wallpaper_status_lock_same_as_home);
            lockStatusCard.setCardBackgroundColor(Color.argb(60, 33, 150, 243));
        } else {
            lockStatusText.setText(R.string.wallpaper_status_lock_inactive);
            lockStatusCard.setCardBackgroundColor(Color.argb(50, 255, 255, 255));
        }
    }
}

