                e.fillInStackTrace()
                withContext(Dispatchers.Main) {
                    Toast.makeText(activity, e.localizedMessage, Toast.LENGTH_LONG).show()
                }
            } finally {
                withContext(Dispatchers.Main) {
                    progressIndicator?.hide()
                }
            }
        } else {
            Log.e(TAG, "Input stream is null. Could not open URI: $contentURI")
        }
    }


    override fun onResume() {
        super.onResume()
        refreshWallpaperStatus()
    }

    private fun refreshWallpaperStatus() {
        val ctx = context ?: return
        val wm = WallpaperManager.getInstance(ctx)
        val pkg = ctx.packageName

        val homeInfo = wm.wallpaperInfo
        val isActiveOnHome = homeInfo != null && homeInfo.packageName == pkg

        val isActiveOnLock: Boolean = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.UPSIDE_DOWN_CAKE) {
            try {
                val lockInfo: WallpaperInfo? = wm.getWallpaperInfo(WallpaperManager.FLAG_LOCK)
                (lockInfo != null && lockInfo.packageName == pkg) || (lockInfo == null && isActiveOnHome)
            } catch (t: Throwable) { isActiveOnHome }
        } else { isActiveOnHome }

        if (isActiveOnHome) {
            homeStatusText?.setText(R.string.wallpaper_status_home_active)
            homeStatusCard?.setCardBackgroundColor(Color.argb(80, 76, 175, 80))
        } else {
            homeStatusText?.setText(R.string.wallpaper_status_home_inactive)
            homeStatusCard?.setCardBackgroundColor(Color.argb(50, 255, 255, 255))
        }

        when {
            isActiveOnLock && isActiveOnHome -> {
                lockStatusText?.setText(R.string.wallpaper_status_lock_active)
                lockStatusCard?.setCardBackgroundColor(Color.argb(80, 33, 150, 243))
            }
            isActiveOnHome -> {
                lockStatusText?.setText(R.string.wallpaper_status_lock_same_as_home)
                lockStatusCard?.setCardBackgroundColor(Color.argb(60, 33, 150, 243))
            }
            else -> {
                lockStatusText?.setText(R.string.wallpaper_status_lock_inactive)
                lockStatusCard?.setCardBackgroundColor(Color.argb(50, 255, 255, 255))
            }
        }
    }

    @SuppressLint("CommitPrefEdits")
    override fun onAttach(context: Context) {
        super.onAttach(context)
        if (prefs == null) {
            prefs = PreferenceManager.getDefaultSharedPreferences(context)
            editor = prefs?.edit()
        }
        prefs?.registerOnSharedPreferenceChangeListener(this)
    }

    override fun onDestroy() {
        super.onDestroy()
        prefs?.unregisterOnSharedPreferenceChangeListener(this)
    }

    @SuppressLint("NotifyDataSetChanged")
    override fun onSharedPreferenceChanged(sharedPreferences: SharedPreferences, key: String?) {
        Log.d(TAG, "onSharedPreferenceChanged: $key")
        if (key == "type") {
            Log.d(TAG, "onSharedPreferenceChanged: notifyDataSetChanged!")
            listAdapter?.updateLocalWallpaper()
            listAdapter?.notifyDataSetChanged()
        }
    }
}

